import{_ as d,o as e,c as a,ae as o}from"./chunks/framework.C7FLYIpo.js";const m=JSON.parse('{"title":"미디어 개요","description":"미디어 생성, 이해 및 음성 기능을 위한 통합 랜딩 페이지","frontmatter":{"title":"미디어 개요","description":"미디어 생성, 이해 및 음성 기능을 위한 통합 랜딩 페이지"},"headers":[],"relativePath":"tools/media-overview.md","filePath":"tools/media-overview.md","lastUpdated":null}'),r={name:"tools/media-overview.md"};function s(i,t,l,n,h,c){return e(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="미디어-생성-및-이해" tabindex="-1">미디어 생성 및 이해 <a class="header-anchor" href="#미디어-생성-및-이해" aria-label="Permalink to &quot;미디어 생성 및 이해&quot;">​</a></h1><p>OpenClaw는 이미지, 비디오, 음악을 생성하고, 인바운드 미디어(이미지, 오디오, 비디오)를 이해하며, 텍스트 음성 변환으로 답변을 큰 소리로 읽습니다. 모든 미디어 기능은 도구 기반입니다: 에이전트가 대화에 따라 사용할 시기를 결정하며, 각 도구는 최소 하나의 백업 프로바이더가 설정된 경우에만 나타납니다.</p><h2 id="기능-한눈에-보기" tabindex="-1">기능 한눈에 보기 <a class="header-anchor" href="#기능-한눈에-보기" aria-label="Permalink to &quot;기능 한눈에 보기&quot;">​</a></h2><table tabindex="0"><thead><tr><th>기능</th><th>도구</th><th>프로바이더</th><th>수행 내용</th></tr></thead><tbody><tr><td>이미지 생성</td><td><code>image_generate</code></td><td>ComfyUI, fal, Google, MiniMax, OpenAI, Vydra</td><td>텍스트 프롬프트나 참조에서 이미지 생성 또는 편집</td></tr><tr><td>비디오 생성</td><td><code>video_generate</code></td><td>Alibaba, BytePlus, ComfyUI, fal, Google, MiniMax, OpenAI, Qwen, Runway, Together, Vydra, xAI</td><td>텍스트, 이미지, 또는 기존 비디오에서 비디오 생성</td></tr><tr><td>음악 생성</td><td><code>music_generate</code></td><td>ComfyUI, Google, MiniMax</td><td>텍스트 프롬프트에서 음악 또는 오디오 트랙 생성</td></tr><tr><td>텍스트 음성 변환 (TTS)</td><td><code>tts</code></td><td>ElevenLabs, Microsoft, MiniMax, OpenAI</td><td>아웃바운드 답변을 음성 오디오로 변환</td></tr><tr><td>미디어 이해</td><td>(자동)</td><td>비전/오디오 지원 모델 프로바이더, CLI 폴백 포함</td><td>인바운드 이미지, 오디오, 비디오 요약</td></tr></tbody></table><h2 id="프로바이더-기능-매트릭스" tabindex="-1">프로바이더 기능 매트릭스 <a class="header-anchor" href="#프로바이더-기능-매트릭스" aria-label="Permalink to &quot;프로바이더 기능 매트릭스&quot;">​</a></h2><p>이 표는 플랫폼 전반에서 어떤 프로바이더가 어떤 미디어 기능을 지원하는지 보여줍니다.</p><table tabindex="0"><thead><tr><th>프로바이더</th><th>이미지</th><th>비디오</th><th>음악</th><th>TTS</th><th>STT / 전사</th><th>미디어 이해</th></tr></thead><tbody><tr><td>Alibaba</td><td></td><td>Yes</td><td></td><td></td><td></td><td></td></tr><tr><td>BytePlus</td><td></td><td>Yes</td><td></td><td></td><td></td><td></td></tr><tr><td>ComfyUI</td><td>Yes</td><td>Yes</td><td>Yes</td><td></td><td></td><td></td></tr><tr><td>Deepgram</td><td></td><td></td><td></td><td></td><td>Yes</td><td></td></tr><tr><td>ElevenLabs</td><td></td><td></td><td></td><td>Yes</td><td></td><td></td></tr><tr><td>fal</td><td>Yes</td><td>Yes</td><td></td><td></td><td></td><td></td></tr><tr><td>Google</td><td>Yes</td><td>Yes</td><td>Yes</td><td></td><td></td><td>Yes</td></tr><tr><td>Microsoft</td><td></td><td></td><td></td><td>Yes</td><td></td><td></td></tr><tr><td>MiniMax</td><td>Yes</td><td>Yes</td><td>Yes</td><td>Yes</td><td></td><td></td></tr><tr><td>OpenAI</td><td>Yes</td><td>Yes</td><td></td><td>Yes</td><td>Yes</td><td>Yes</td></tr><tr><td>Qwen</td><td></td><td>Yes</td><td></td><td></td><td></td><td></td></tr><tr><td>Runway</td><td></td><td>Yes</td><td></td><td></td><td></td><td></td></tr><tr><td>Together</td><td></td><td>Yes</td><td></td><td></td><td></td><td></td></tr><tr><td>Vydra</td><td>Yes</td><td>Yes</td><td></td><td></td><td></td><td></td></tr><tr><td>xAI</td><td></td><td>Yes</td><td></td><td></td><td></td><td></td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">NOTE</p><p>미디어 이해는 프로바이더 설정에 등록된 비전 또는 오디오 지원 모델을 사용합니다. 위 표는 전용 미디어 이해 지원이 있는 프로바이더를 강조합니다; 멀티모달 모델(Anthropic, Google, OpenAI 등)이 있는 대부분의 LLM 프로바이더도 활성 답변 모델로 설정된 경우 인바운드 미디어를 이해할 수 있습니다.</p></div><h2 id="비동기-생성-작동-방식" tabindex="-1">비동기 생성 작동 방식 <a class="header-anchor" href="#비동기-생성-작동-방식" aria-label="Permalink to &quot;비동기 생성 작동 방식&quot;">​</a></h2><p>비디오 및 음악 생성은 프로바이더 처리가 일반적으로 30초에서 몇 분 걸리기 때문에 백그라운드 태스크로 실행됩니다. 에이전트가 <code>video_generate</code> 또는 <code>music_generate</code>를 호출하면 OpenClaw는 프로바이더에 요청을 제출하고, 즉시 태스크 ID를 반환하며, 태스크 원장에서 작업을 추적합니다. 에이전트는 작업이 실행되는 동안 다른 메시지에 계속 응답합니다. 프로바이더가 완료되면 OpenClaw가 에이전트를 깨워 완성된 미디어를 원래 채널에 다시 게시할 수 있습니다. 이미지 생성 및 TTS는 동기적이며 답변과 함께 인라인으로 완료됩니다.</p><h2 id="빠른-링크" tabindex="-1">빠른 링크 <a class="header-anchor" href="#빠른-링크" aria-label="Permalink to &quot;빠른 링크&quot;">​</a></h2><ul><li><a href="/openclaw-docs-ko/tools/image-generation">이미지 생성</a> -- 이미지 생성 및 편집</li><li><a href="/openclaw-docs-ko/tools/video-generation">비디오 생성</a> -- 텍스트-비디오, 이미지-비디오, 비디오-비디오</li><li><a href="/openclaw-docs-ko/tools/music-generation">음악 생성</a> -- 음악 및 오디오 트랙 생성</li><li><a href="/openclaw-docs-ko/tools/tts">텍스트 음성 변환</a> -- 답변을 음성 오디오로 변환</li><li><a href="/openclaw-docs-ko/nodes/media-understanding">미디어 이해</a> -- 인바운드 이미지, 오디오, 비디오 이해</li></ul>',12)])])}const Y=d(r,[["render",s]]);export{m as __pageData,Y as default};
